import{_ as a,o as i,c as n,a6 as t}from"./chunks/framework.DtxWasON.js";const p=JSON.parse('{"title":"What is Mainchain?","description":"","frontmatter":{},"headers":[],"relativePath":"mainchain/introduction/about-mainchain.md","filePath":"mainchain/introduction/about-mainchain.md"}'),o={name:"mainchain/introduction/about-mainchain.md"};function r(s,e,c,l,d,h){return i(),n("div",null,[...e[0]||(e[0]=[t('<h1 id="what-is-mainchain" tabindex="-1">What is Mainchain? <a class="header-anchor" href="#what-is-mainchain" aria-label="Permalink to &quot;What is Mainchain?&quot;">​</a></h1><p>Mainchain is the backbone of the Unification Network. It is a Cosmos SDK based chain, and is where WrkChains and BEACONs submit their hashes, and FUND transactions take place.</p><blockquote><p>Mainchain is a public proof-of-stake chain. The core coin used for staking, rewards, and network fees is FUND. The on-chain denomination is <code>nund</code> (Nano Unification Denomination) which is 10^-9 FUND.</p></blockquote><h2 id="networks" tabindex="-1">Networks <a class="header-anchor" href="#networks" aria-label="Permalink to &quot;Networks&quot;">​</a></h2><p>There are currently two live public Mainchain networks, and one private development network:</p><h4 id="mainnet" tabindex="-1">MainNet <a class="header-anchor" href="#mainnet" aria-label="Permalink to &quot;MainNet&quot;">​</a></h4><p>Launched on 14/05/2020, <a href="https://github.com/unification-com/mainnet" target="_blank" rel="noreferrer">FUND-MainNet</a> is the live public Unification <strong>Main Network</strong>.</p><h4 id="testnet" tabindex="-1">Testnet <a class="header-anchor" href="#testnet" aria-label="Permalink to &quot;Testnet&quot;">​</a></h4><p>Launched in Q4 2019, <a href="https://github.com/unification-com/testnet" target="_blank" rel="noreferrer">FUND-TestNet</a> serves as the official Unification public <strong>Test network</strong>, where developers can test WRKChains/BEACONs or third party application such as wallets and block explorers before deploying on MainNet. It also serves as a test platform for Mainchain developers to test updates and new features to the Mainchain code in a live environment.</p><h4 id="devnet" tabindex="-1">DevNet <a class="header-anchor" href="#devnet" aria-label="Permalink to &quot;DevNet&quot;">​</a></h4><p>Additionally, the <a href="https://github.com/unification-com/mainchain" target="_blank" rel="noreferrer">Mainchain repository</a> comes with a full private <a href="./local-devnet.html">DevNet</a> - a completely self-contained network for development and testing Mainchain features.</p><h2 id="software" tabindex="-1">Software <a class="header-anchor" href="#software" aria-label="Permalink to &quot;Software&quot;">​</a></h2><p>The Mainchain suite comes with a unified binary: <code>und</code> (&quot;<code>Un</code>ification <code>D</code>aemon&quot;). This binary is used for running the server-side daemon (e.g. for Validator nodes, seeds, sentries, RPCs etc.), and as a client to interact with the network (e.g. for sending queries and generating and broadcasting transactions).</p><p>Mainchain has been built with the following core Cosmos SDK modules:</p><ul><li><code>x/auth</code>: Accounts and signatures.</li><li><code>x/bank</code>: Token transfers.</li><li><code>x/staking</code>: Staking logic.</li><li><code>x/distribution</code>: Fee distribution logic.</li><li><code>x/slashing</code>: Slashing logic.</li><li><code>x/gov</code>: on-chain governance logic.</li><li><code>x/supply</code>: FUND Coin supply logic</li><li><code>x/params</code>: Handles module-level parameters, which can be modified via governance.</li><li><code>x/crisis</code>: Handles potential network errors during the early days of deployment</li><li><code>x/upgrade</code>: Handles processing software upgrades and associated state migrations</li></ul><p>Unification have also developed the following modules for Mainchain:</p><ul><li><code>x/beacon</code>: BEACON hash timestamp submission logic</li><li><code>x/enterprise</code>: Handles purchasing, locking and unlocking of Enterprise FUND</li><li><code>x/wrkchain</code>: WRKChain block hash submission handling</li></ul>',17)])])}const f=a(o,[["render",r]]);export{p as __pageData,f as default};
